import stylesText from './nutrition-edit.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { MEAL_TYPES } from '@motivation/shared';
import type { NutritionEntry, MealType } from '@motivation/shared';
import { nutritionEntryToFormData } from '../food-serving-form/food-serving-form.types.js';
import '../food-serving-form/food-serving-form.component.js';
import type { FoodServingForm } from '../food-serving-form/food-serving-form.component.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="edit-container">
        <div class="edit-header">
            <h3>Edit Entry</h3>
            <span class="source-badge" id="source-badge"></span>
        </div>

        <input type="text" id="food-name" class="food-name-input" placeholder="Food name">

        <food-serving-form id="serving-form" editable></food-serving-form>

        <div class="form-row">
            <div class="form-group">
                <label for="meal-type">Meal</label>
                <select id="meal-type" class="form-select">
                    ${MEAL_TYPES.map(m => `<option value="${m}">${m}</option>`).join('\n                    ')}
                </select>
            </div>
        </div>

        <div class="action-buttons">
            <button class="btn-delete" id="btn-delete">Delete</button>
            <button class="btn-save" id="btn-save">Save</button>
        </div>
    </div>
`;

const SOURCE_LABELS: Record<string, string> = {
    manual: 'Manual',
    openfoodfacts: 'Open Food Facts',
    ai_estimate: 'AI Estimate',
};

export class NutritionEdit extends HTMLElement {
    private _entry: NutritionEntry | null = null;
    private _onSave: ((id: number, updates: Partial<NutritionEntry>) => void) | null = null;
    private _onDelete: ((id: number) => void) | null = null;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));
    }

    connectedCallback() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('btn-save')!.addEventListener('click', () => this.handleSave());
        shadow.getElementById('btn-delete')!.addEventListener('click', () => this.handleDelete());
    }

    set onSave(handler: (id: number, updates: Partial<NutritionEntry>) => void) {
        this._onSave = handler;
    }

    set onDelete(handler: (id: number) => void) {
        this._onDelete = handler;
    }

    set entry(val: NutritionEntry) {
        this._entry = val;
        this.populateForm();
    }

    get entry(): NutritionEntry | null {
        return this._entry;
    }

    private populateForm(): void {
        const e = this._entry;
        if (!e) return;
        const shadow = this.shadowRoot!;

        // Source badge
        shadow.getElementById('source-badge')!.textContent = SOURCE_LABELS[e.source] ?? e.source;

        // Food name
        const nameInput = shadow.getElementById('food-name') as HTMLInputElement;
        nameInput.value = e.food_name ?? '';
        nameInput.readOnly = e.source === 'openfoodfacts';

        // Meal type
        (shadow.getElementById('meal-type') as HTMLSelectElement).value = e.meal_type;

        // Serving form
        const form = shadow.getElementById('serving-form') as FoodServingForm;
        form.data = nutritionEntryToFormData(e);
    }

    private handleSave(): void {
        if (!this._entry || !this._onSave) return;
        const shadow = this.shadowRoot!;

        const form = shadow.getElementById('serving-form') as FoodServingForm;
        const { servingAmount, serving } = form.getCurrentValues();
        const formData = (form as any)._data;
        const servingByWeight = formData?.servingByWeight ?? false;

        const updates: Partial<NutritionEntry> = {
            food_name: (shadow.getElementById('food-name') as HTMLInputElement).value.trim(),
            meal_type: (shadow.getElementById('meal-type') as HTMLSelectElement).value as MealType,
            ...serving,
        };

        if (servingByWeight) {
            updates.serving_size = `${Math.round(servingAmount)}g`;
        }

        this._onSave(this._entry.id, updates);
    }

    private handleDelete(): void {
        if (!this._entry || !this._onDelete) return;
        if (confirm(`Delete "${this._entry.food_name}"?`)) {
            this._onDelete(this._entry.id);
        }
    }
}

customElements.define('nutrition-edit', NutritionEdit);
